INSERT INTO weiyutixing (addtime, yonghuzhanghao, yonghuxingming, tixingbiaoti, tixingriqi, tixingneirong) VALUES
('2026-05-10 09:15:00', '12', 'Test User', '血红龙鱼换水提醒', '2026-05-18', '您的血红龙鱼缸已运行7天，建议本周日换水1/4，同时添加硝化细菌稳定水质。换水时注意新水温度与缸内温差不超过2°C。'),
('2026-05-10 10:30:00', '12', 'Test User', '孔雀鱼喂食提醒', '2026-05-16', '孔雀鱼每日需喂食2次，建议上午9点和下午5点各投喂一次薄片饲料，每次投喂量以3分钟内吃完为宜，避免残饵污染水质。'),
('2026-05-10 14:20:00', '12', 'Test User', '锦鲤过滤棉清洗', '2026-05-22', '锦鲤池过滤棉已使用两周，建议取出用清水冲洗（勿用自来水直接冲洗生化棉），避免堵塞影响硝化系统正常运行。'),
('2026-05-11 08:45:00', '12', 'Test User', '暹罗斗鱼温度监控', '2026-05-17', '斗鱼适宜温度24-28°C，近日气温变化较大，请检查加热棒和温度计是否正常工作，温差骤变可能导致白点病。'),
('2026-05-11 11:00:00', '12', 'Test User', '小丑鱼海盐调配', '2026-05-25', '海水缸盐度建议维持在1.023-1.025，请使用光学盐度计检测并适当补充海盐，换水时新配海水需提前静置24小时。'),
('2026-05-11 16:30:00', '12', 'Test User', '蓝倒吊藻类管理', '2026-05-28', '蓝倒吊喜食藻类，若缸壁藻类过多可引入食藻螺或吊类鱼辅助清理，同时控制光照时长在8-10小时，避免爆藻。'),
('2026-05-12 09:00:00', '12', 'Test User', '罗汉鱼增色饲料', '2026-06-01', '罗汉鱼成鱼期建议搭配增色饲料（含虾红素和螺旋藻），每日1-2次，有助于头部隆起发育和体色鲜艳。避免过量喂食。'),
('2026-05-12 10:15:00', '12', 'Test User', '金龙鱼水质检测', '2026-05-20', '金龙鱼对水质要求极高，建议每周检测pH值（适宜6.5-7.5）和氨氮含量（应低于0.02mg/L），发现超标及时换水1/3。'),
('2026-05-12 15:40:00', '12', 'Test User', '月光鱼繁殖隔离', '2026-06-05', '月光鱼为卵胎生，若发现母鱼腹部明显膨大且胎斑变深，建议2-3天内放入繁殖隔离盒待产，产后及时捞出母鱼避免吞食幼鱼。'),
('2026-05-13 08:30:00', '12', 'Test User', '虎皮鱼群体观察', '2026-05-30', '虎皮鱼喜群游且有一定攻击性，建议保持6条以上同缸饲养以分散攻击，注意观察是否有个体被追咬致鳍条破损，必要时隔离受伤个体。'),
('2026-05-13 10:50:00', '12', 'Test User', '招财鱼投喂调整', '2026-06-10', '招财鱼食量较大，成鱼每日喂食1次即可，建议以高品质颗粒饲料为主搭配少量冻虾，每周停食1天有助于消化系统休息。'),
('2026-05-13 14:00:00', '12', 'Test User', '玛丽鱼盐浴预防', '2026-06-15', '玛丽鱼耐盐性较好，每月可进行一次预防性盐浴：每10L水添加5-10g粗盐，浸泡15-20分钟后放回原缸，有助于预防寄生虫和霉菌感染。'),
('2026-05-14 09:20:00', '12', 'Test User', '雷龙鱼跳缸防护', '2026-05-19', '雷龙鱼跳跃能力极强，受惊时尤其容易跳出鱼缸。请确保缸盖密封良好，可在盖板与缸沿间加装防跳网，投喂时注意轻缓操作避免惊吓。'),
('2026-05-14 11:35:00', '12', 'Test User', '血红龙鱼灯光调整', '2026-06-08', '红龙鱼建议使用暖色调LED灯（色温6500K以下），每日光照8-10小时有助于促进发色。夜间留微弱夜灯避免鱼只受惊撞缸。'),
('2026-05-14 13:10:00', '12', 'Test User', '锦鲤春季驱虫', '2026-07-01', '春季水温回升至18°C以上时寄生虫活跃，建议进行一次预防性驱虫：可用甲苯咪唑按说明书比例药浴，药浴期间停食并加大充氧。');
